targets.query:
created = from(bucket: "nsx") |> range(start: -7d) |> filter(fn: (r) => r._measurement == "nsx_t1_event" and r.event == "created" and r._field == "count") |> filter(fn: (r) => r.site =~ /^${site:regex}$/) |> group() |> sum() |> findRecord(fn: (key) => true, idx: 0)
deleted = from(bucket: "nsx") |> range(start: -7d) |> filter(fn: (r) => r._measurement == "nsx_t1_event" and r.event == "deleted" and r._field == "count") |> filter(fn: (r) => r.site =~ /^${site:regex}$/) |> group() |> sum() |> findRecord(fn: (key) => true, idx: 0)
from(bucket: "nsx") |> range(start: -1m) |> limit(n: 1) |> map(fn: (r) => ({r with _value: created._value - deleted._value}))
